import { describe, expect, it } from '@a0n/gnosis/test';
import {
  activeLanesFromPackedGrassmannianLaneMask,
  boundaryMagnitudeParity,
  createPackedGrassmannianLaneMask,
  decideTopologicalXorSkip,
  fidelityToPerthou,
  issueGrassmannianXorRoundCertificate,
  issueGrassmannianXorRoundCertificateFromMask,
  issueActivationTraceXorCertificate,
  issueTopologicalXorCertificate,
  MONSTER_GRASSMANNIAN_LANE_COUNT,
  packedGrassmannianLaneMaskDefectRank,
  packedGrassmannianLaneMaskFromActiveLanes,
  planTopologicalXorSkips,
  projectionErrorPerthou,
  reviewProjectedTopologicalXorCertificate,
  togglePackedGrassmannianLane,
  topologicalXorBoundariesFromActivationTrace,
  topologicalXorBoundariesFromCounts,
  topologicalXorBoundaryKey,
  verifyTopologicalXorCertificate,
  xorPackedGrassmannianLaneMasks,
} from './topological-xor-certificate';
import type { ActivationTrace } from './scheduling-mesh';

describe('Topological XOR Certificate', () => {
  it('cancels paired boundaries over F2', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-balanced',
      target: 'agent://fork-race-fold/session-1',
      boundaries: [
        { label: 'fork-a', source: 'agent-task-graph' },
        { label: 'fork-a', source: 'agent-task-graph' },
        { label: 'fold-b', dimension: 2, magnitude: 4 },
      ],
    });

    expect(certificate.balanced).toBe(true);
    expect(certificate.status).toBe('measured');
    expect(certificate.defectRank).toBe(0);
    expect(certificate.parityClass).toBe('0');
    expect(verifyTopologicalXorCertificate(certificate)).toBe(true);
  });

  it('surfaces unresolved odd boundary classes as failed certificates', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-defect',
      target: 'model://qwen-boundary-scan',
      boundaries: [
        { label: 'layer-3', dimension: 3, magnitude: 2 },
        { label: 'layer-4', dimension: 4, magnitude: 3 },
        { label: 'layer-5', dimension: 5 },
      ],
    });

    expect(certificate.balanced).toBe(false);
    expect(certificate.status).toBe('failed');
    expect(certificate.defectRank).toBe(2);
    expect(certificate.parityClass).toBe('4:layer-4 xor 5:layer-5');
    expect(certificate.unresolvedBoundaries.map((boundary) => boundary.key)).toEqual([
      '4:layer-4',
      '5:layer-5',
    ]);
    expect(verifyTopologicalXorCertificate(certificate)).toBe(true);
  });

  it('keeps balanced projected evidence out of measured status', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-projected',
      target: 'runtime://compression-candidate',
      boundaries: [
        { label: 'candidate-a', status: 'projected' },
        { label: 'candidate-a', status: 'projected' },
      ],
    });

    expect(certificate.balanced).toBe(true);
    expect(certificate.status).toBe('projected');
    expect(certificate.projectedBoundaryCount).toBe(2);
  });

  it('derives void-boundary inputs from counts', () => {
    const boundaries = topologicalXorBoundariesFromCounts([2, 3, 4], {
      targetPrefix: 'void',
    });
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-void',
      target: 'void://boundary',
      boundaries,
    });

    expect(boundaries.map(topologicalXorBoundaryKey)).toEqual([
      '0:void-0',
      '1:void-1',
      '2:void-2',
    ]);
    expect(certificate.defectRank).toBe(1);
    expect(certificate.parityClass).toBe('1:void-1');
  });

  it('computes magnitude parity over safe integers', () => {
    expect(boundaryMagnitudeParity({ label: 'zero', magnitude: 0 })).toBe(0);
    expect(boundaryMagnitudeParity({ label: 'negative', magnitude: -3 })).toBe(1);
    expect(() =>
      boundaryMagnitudeParity({ label: 'float', magnitude: 1.5 })
    ).toThrow('boundary.magnitude must be a safe integer');
  });

  it('demotes a projected certificate when measured parity fails', () => {
    const projected = issueTopologicalXorCertificate({
      certificateId: 'txor-projected-qwen-coder',
      target: 'model://qwen-coder-7b/k5',
      boundaries: [
        { label: 'candidate-a', status: 'projected' },
        { label: 'candidate-a', status: 'projected' },
      ],
    });
    const measured = issueTopologicalXorCertificate({
      certificateId: 'txor-measured-qwen-coder',
      target: 'model://qwen-coder-7b/k5',
      boundaries: [{ label: 'candidate-a', status: 'measured' }],
    });

    const review = reviewProjectedTopologicalXorCertificate({
      reviewId: 'review-qwen-coder-wave-4',
      projectedCertificate: projected,
      measuredCertificate: measured,
      projectedFidelityPerthou: fidelityToPerthou(40, 100),
      measuredFidelityPerthou: fidelityToPerthou(0, 30),
    });

    expect(projected.status).toBe('projected');
    expect(measured.status).toBe('failed');
    expect(review.status).toBe('demoted-after-measurement');
    expect(review.projectionErrorPerthou).toBe(400);
    expect(review.reason).toBe('measured parity certificate failed');
  });

  it('promotes a projected certificate after measured parity and fidelity clear', () => {
    const projected = issueTopologicalXorCertificate({
      certificateId: 'txor-projected-pass',
      target: 'runtime://candidate-pass',
      boundaries: [
        { label: 'boundary-a', status: 'projected' },
        { label: 'boundary-a', status: 'projected' },
      ],
    });
    const measured = issueTopologicalXorCertificate({
      certificateId: 'txor-measured-pass',
      target: 'runtime://candidate-pass',
      boundaries: [
        { label: 'boundary-a', status: 'measured' },
        { label: 'boundary-a', status: 'measured' },
      ],
    });

    const review = reviewProjectedTopologicalXorCertificate({
      reviewId: 'review-pass',
      projectedCertificate: projected,
      measuredCertificate: measured,
      projectedFidelityPerthou: 960,
      measuredFidelityPerthou: 975,
    });

    expect(review.status).toBe('promoted-after-measurement');
    expect(review.projectionErrorPerthou).toBe(15);
  });

  it('keeps projection review under investigation without measured evidence', () => {
    const projected = issueTopologicalXorCertificate({
      certificateId: 'txor-projected-a',
      target: 'runtime://candidate-investigation',
      boundaries: [
        { label: 'boundary-a', status: 'projected' },
        { label: 'boundary-a', status: 'projected' },
      ],
    });
    const stillProjected = issueTopologicalXorCertificate({
      certificateId: 'txor-projected-b',
      target: 'runtime://candidate-investigation',
      boundaries: [
        { label: 'boundary-a', status: 'projected' },
        { label: 'boundary-a', status: 'projected' },
      ],
    });

    const review = reviewProjectedTopologicalXorCertificate({
      reviewId: 'review-investigation',
      projectedCertificate: projected,
      measuredCertificate: stillProjected,
    });

    expect(review.status).toBe('under-investigation');
    expect(review.projectionErrorPerthou).toBeUndefined();
  });

  it('computes fidelity projection error in perthou', () => {
    expect(fidelityToPerthou(40, 100)).toBe(400);
    expect(fidelityToPerthou(0, 30)).toBe(0);
    expect(projectionErrorPerthou(400, 0)).toBe(400);
  });

  it('skips reconstruction for measured balanced XOR certificates', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-skip-measured',
      target: 'runtime://trace-cache',
      boundaries: [
        { label: 'fork-fold-a', status: 'measured' },
        { label: 'fork-fold-a', status: 'measured' },
      ],
    });

    const decision = decideTopologicalXorSkip({ certificate });

    expect(decision.action).toBe('skip-reconstruction');
    expect(decision.canSkip).toBe(true);
    expect(decision.speculative).toBe(false);
    expect(decision.projectionDebt).toBe(false);
    expect(decision.unresolvedBoundaryKeys).toEqual([]);
  });

  it('keeps projected balanced XOR certificates on measurement path by default', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-skip-projected-held',
      target: 'runtime://speculative-trace-cache',
      boundaries: [
        { label: 'fork-fold-a', status: 'projected' },
        { label: 'fork-fold-a', status: 'projected' },
      ],
    });

    const decision = decideTopologicalXorSkip({ certificate });

    expect(decision.action).toBe('measure-before-skip');
    expect(decision.canSkip).toBe(false);
    expect(decision.speculative).toBe(true);
    expect(decision.projectionDebt).toBe(true);
  });

  it('allows projected skip only when projection debt is explicit', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-skip-projected-accepted',
      target: 'runtime://speculative-fast-path',
      boundaries: [
        { label: 'fork-fold-a', status: 'projected' },
        { label: 'fork-fold-a', status: 'projected' },
      ],
    });

    const decision = decideTopologicalXorSkip({
      certificate,
      allowProjectedSkip: true,
    });

    expect(decision.action).toBe('skip-with-projection-debt');
    expect(decision.canSkip).toBe(true);
    expect(decision.speculative).toBe(true);
    expect(decision.projectionDebt).toBe(true);
  });

  it('reconstructs unresolved odd XOR boundary classes', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-skip-defect',
      target: 'runtime://trace-defect',
      boundaries: [{ label: 'fork-fold-a', status: 'measured' }],
    });

    const decision = decideTopologicalXorSkip({ certificate });

    expect(decision.action).toBe('reconstruct-boundary');
    expect(decision.canSkip).toBe(false);
    expect(decision.unresolvedBoundaryKeys).toEqual(['fork-fold-a']);
  });

  it('requires measured fidelity when a skip threshold is supplied', () => {
    const certificate = issueTopologicalXorCertificate({
      certificateId: 'txor-skip-fidelity',
      target: 'runtime://trace-fidelity',
      boundaries: [
        { label: 'fork-fold-a', status: 'measured' },
        { label: 'fork-fold-a', status: 'measured' },
      ],
    });

    expect(
      decideTopologicalXorSkip({
        certificate,
        requireMeasuredFidelityPerthou: 950,
      }).action
    ).toBe('measure-before-skip');
    expect(
      decideTopologicalXorSkip({
        certificate,
        requireMeasuredFidelityPerthou: 950,
        measuredFidelityPerthou: 951,
      }).action
    ).toBe('skip-reconstruction');
  });

  it('plans smart skips, measurements, and reconstructions in one pass', () => {
    const measuredClosed = issueTopologicalXorCertificate({
      certificateId: 'txor-plan-measured',
      target: 'runtime://closed',
      boundaries: [
        { label: 'a', status: 'measured' },
        { label: 'a', status: 'measured' },
      ],
    });
    const projectedClosed = issueTopologicalXorCertificate({
      certificateId: 'txor-plan-projected',
      target: 'runtime://projected',
      boundaries: [
        { label: 'b', status: 'projected' },
        { label: 'b', status: 'projected' },
      ],
    });
    const openBoundary = issueTopologicalXorCertificate({
      certificateId: 'txor-plan-open',
      target: 'runtime://open',
      boundaries: [{ label: 'c', status: 'measured' }],
    });

    const plan = planTopologicalXorSkips({
      decisions: [
        decideTopologicalXorSkip({ certificate: measuredClosed }),
        decideTopologicalXorSkip({ certificate: projectedClosed }),
        decideTopologicalXorSkip({ certificate: openBoundary }),
      ],
    });

    expect(plan.skipTargets).toEqual(['runtime://closed']);
    expect(plan.retainedSkipTargets).toEqual(['runtime://closed']);
    expect(plan.recomputableSkipTargets).toEqual([]);
    expect(plan.measureTargets).toEqual(['runtime://projected']);
    expect(plan.reconstructTargets).toEqual(['runtime://open']);
    expect(plan.acceptedProjectionDebtTargets).toEqual([]);
    expect(plan.unresolvedBoundaryKeys).toEqual(['c']);
    expect(plan.canSkipAll).toBe(false);
    expect(plan.hasProjectionDebt).toBe(true);
  });

  it('plans accepted projected skips as projection debt', () => {
    const projectedClosed = issueTopologicalXorCertificate({
      certificateId: 'txor-plan-projected-debt',
      target: 'runtime://projected-fast-path',
      boundaries: [
        { label: 'b', status: 'projected' },
        { label: 'b', status: 'projected' },
      ],
    });

    const plan = planTopologicalXorSkips({
      decisions: [
        decideTopologicalXorSkip({
          certificate: projectedClosed,
          allowProjectedSkip: true,
        }),
      ],
    });

    expect(plan.skipTargets).toEqual(['runtime://projected-fast-path']);
    expect(plan.retainedSkipTargets).toEqual(['runtime://projected-fast-path']);
    expect(plan.recomputableSkipTargets).toEqual([]);
    expect(plan.acceptedProjectionDebtTargets).toEqual([
      'runtime://projected-fast-path',
    ]);
    expect(plan.measureTargets).toEqual([]);
    expect(plan.reconstructTargets).toEqual([]);
    expect(plan.canSkipAll).toBe(true);
    expect(plan.hasProjectionDebt).toBe(true);
  });

  it('keeps only the highest-priority skip targets under retention budget', () => {
    const closedA = issueTopologicalXorCertificate({
      certificateId: 'txor-budget-a',
      target: 'runtime://closed-a',
      boundaries: [
        { label: 'a', status: 'measured' },
        { label: 'a', status: 'measured' },
      ],
    });
    const closedB = issueTopologicalXorCertificate({
      certificateId: 'txor-budget-b',
      target: 'runtime://closed-b',
      boundaries: [
        { label: 'b', status: 'measured' },
        { label: 'b', status: 'measured' },
      ],
    });
    const closedC = issueTopologicalXorCertificate({
      certificateId: 'txor-budget-c',
      target: 'runtime://closed-c',
      boundaries: [
        { label: 'c', status: 'measured' },
        { label: 'c', status: 'measured' },
      ],
    });

    const plan = planTopologicalXorSkips({
      decisions: [
        decideTopologicalXorSkip({ certificate: closedA }),
        decideTopologicalXorSkip({ certificate: closedB }),
        decideTopologicalXorSkip({ certificate: closedC }),
      ],
      retentionBudget: 2,
      priorityByTarget: {
        'runtime://closed-a': 10,
        'runtime://closed-b': 30,
        'runtime://closed-c': 20,
      },
    });

    expect(plan.skipTargets).toEqual([
      'runtime://closed-a',
      'runtime://closed-b',
      'runtime://closed-c',
    ]);
    expect(plan.retainedSkipTargets).toEqual([
      'runtime://closed-b',
      'runtime://closed-c',
    ]);
    expect(plan.recomputableSkipTargets).toEqual(['runtime://closed-a']);
  });

  it('certifies balanced fork/fold activation traces', () => {
    const trace: ActivationTrace<string> = {
      startHub: 0,
      totalHops: 1,
      cellsActivated: 1,
      results: ['ok'],
      firings: [
        { hub: 0, type: 'fork', hop: 0 },
        { hub: 0, type: 'race', hop: 0, winner: 1 },
        { hub: 0, type: 'fold', hop: 0 },
      ],
    };

    const certificate = issueActivationTraceXorCertificate({
      certificateId: 'txor-trace-balanced',
      target: 'activation://balanced',
      trace,
    });

    expect(topologicalXorBoundariesFromActivationTrace(trace)).toHaveLength(2);
    expect(certificate.status).toBe('measured');
    expect(certificate.balanced).toBe(true);
  });

  it('fails activation traces with a fork that never folds back', () => {
    const trace: ActivationTrace<string> = {
      startHub: 0,
      totalHops: 1,
      cellsActivated: 0,
      results: [],
      firings: [
        { hub: 0, type: 'fork', hop: 0 },
        { hub: 0, type: 'race', hop: 0, winner: 1 },
      ],
    };

    const certificate = issueActivationTraceXorCertificate({
      certificateId: 'txor-trace-unbalanced',
      target: 'activation://unbalanced',
      trace,
    });

    expect(certificate.status).toBe('failed');
    expect(certificate.defectRank).toBe(1);
    expect(certificate.parityClass).toBe(
      '0:activation:0:hub:0:hop:0:fork-fold'
    );
  });

  it('projects a resident cannon round into Grassmannian XOR parity', () => {
    const certificate = issueGrassmannianXorRoundCertificate({
      roundId: 'monster-196884',
      chart: 'amplituhedron-window',
      laneCount: MONSTER_GRASSMANNIAN_LANE_COUNT,
      activeLaneIndices: [0, 1, 1, MONSTER_GRASSMANNIAN_LANE_COUNT - 1],
    });

    expect(certificate.target).toBe(
      'grassmannian://amplituhedron-window/round/monster-196884'
    );
    expect(certificate.status).toBe('failed');
    expect(certificate.defectRank).toBe(2);
    expect(certificate.parityClass).toBe(
      '0:amplituhedron-window:plucker-lane-0 xor 196883:amplituhedron-window:plucker-lane-196883'
    );
    expect(certificate.theoremRefs).toContain(
      'Gnosis.GrassmannianCompiler.amplituhedron_volume_equivalence'
    );
  });

  it('keeps full Monster Grassmannian channel parity packed until certificate export', () => {
    const mask = createPackedGrassmannianLaneMask();
    expect(mask.laneCount).toBe(MONSTER_GRASSMANNIAN_LANE_COUNT);
    expect(mask.words.length).toBe(Math.ceil(MONSTER_GRASSMANNIAN_LANE_COUNT / 32));

    togglePackedGrassmannianLane(mask, 0);
    togglePackedGrassmannianLane(mask, 1);
    togglePackedGrassmannianLane(mask, 1);
    togglePackedGrassmannianLane(mask, MONSTER_GRASSMANNIAN_LANE_COUNT - 1);

    expect(packedGrassmannianLaneMaskDefectRank(mask)).toBe(2);
    expect(activeLanesFromPackedGrassmannianLaneMask(mask)).toEqual([
      0,
      MONSTER_GRASSMANNIAN_LANE_COUNT - 1,
    ]);

    const certificate = issueGrassmannianXorRoundCertificateFromMask({
      roundId: 'monster-packed',
      chart: 'amplituhedron-window',
      mask,
    });

    expect(certificate.defectRank).toBe(2);
    expect(certificate.parityClass).toBe(
      '0:amplituhedron-window:plucker-lane-0 xor 196883:amplituhedron-window:plucker-lane-196883'
    );
  });

  it('xors packed Grassmannian masks without expanding lane objects', () => {
    const left = packedGrassmannianLaneMaskFromActiveLanes(128, [2, 64, 127]);
    const right = packedGrassmannianLaneMaskFromActiveLanes(128, [64, 65, 127]);
    const folded = xorPackedGrassmannianLaneMasks(left, right);

    expect(activeLanesFromPackedGrassmannianLaneMask(folded)).toEqual([2, 65]);
    expect(packedGrassmannianLaneMaskDefectRank(folded)).toBe(2);
  });
});
